public void delete(boolean _showInfoDelReserv)
{
    next delete(_showInfoDelReserv);

    if(ETGcanadaparameters::find().EnableDeleteValidations && this.ETGParentProdId)
    {
        ProdTable prodTable;

        changecompany(this.ETGParentEntity)
        {
            ttsbegin;
            select firstonly prodTable
                where prodTable.ProdId == this.ETGParentProdId
                && prodTable.ProdStatus== ProdStatus::Created;

            if(prodTable)
            {
                ttsbegin;
                prodTable.selectForUpdate(true);
                prodTable.delete();
                ttscommit;
            }
            ttscommit;
        }
    }
}
